// @mui
import { styled } from "@mui/material/styles";

// components
import Page from "../../components/Page";
// sections
import { Box, Typography, Stack } from "@mui/material";

import Footer from "../../components/onboarding/footer";
import { useNavigate } from "react-router";
import TextField from "../../components/core/LabeledInput";
import AdapterDateFns from "@mui/lab/AdapterDateFns";
import LocalizationProvider from "@mui/lab/LocalizationProvider";
import * as Yup from "yup";
import { useFormik, Form, FormikProvider } from "formik";
import { useDispatch ,useSelector} from "react-redux";
import { updateOnboarding } from "../../redux/actions/Onboarding";
import MobileDatePicker from "@mui/lab/MobileDatePicker";
// ----------------------------------------------------------------------
import Header from "../../components/onboarding/header";
const RootStyle = styled("div")(() => ({
  display: "flex",
  flexDirection: "column",
  flex: 1,
  flexGrow: 1,
  background: "#fff",
  height: "100vh",
}));

const BoxStyle = styled(Box)(() => ({
  position: "relative",
}));

const InsideBoxStyle = styled(Box)(() => ({
  position: "absolute",
  width: "100%",
  display: "flex",
  justifyContent: "center",
  alignItems: "center",
  flexDirection: "column",
  paddingTop: 52,
  paddingBottom: 24,
  zIndex: 100,
  top: 0,
}));

// ----------------------------------------------------------------------

export default function HomePage() {
  const navigate = useNavigate();
  const dispatch = useDispatch();
  const RegisterSchema = Yup.object().shape({
    firstName: Yup.string().required("First Name is required"),
    lastName: Yup.string().required("Last Name is required"),
    dob: Yup.string().required("Birthday is required"),
  });
let userData=useSelector(s=>s.Onboarding)
  const formik = useFormik({
    initialValues: {
      firstName: userData.name?.split(" ")?.[0],
      lastName: userData.name.split(" ")?.[1],
      dob: new Date(),
    },
    validationSchema: RegisterSchema,
    onSubmit: async (values, { setErrors, setSubmitting }) => {
      dispatch(
        updateOnboarding({
          name: values.firstName + " " + values.lastName,
          DOB: values.dob,
        })
      );
      navigate("/onboarding/profile-pic");
    },
  });

  const {
    errors,
    touched,
    handleSubmit,
    isSubmitting,
    getFieldProps,
    setFieldValue,
    values,
  } = formik;
  return (
    <Page title="The starting point for your next fitness gig">
      <FormikProvider value={formik}>
        <Form autoComplete="off" noValidate onSubmit={handleSubmit}>
          <RootStyle>
            <Header
              title={"Create new account"}
              onClose={() => navigate("/")}
            />
            <Box
              display={"flex"}
              height={"100%"}
              flexDirection={"column"}
              alignItems={"center"}
              flexGrow={"1"}
              px={2}
            >
              <Typography variant="h2" sx={{ my: 6 }}>
                Personal information
              </Typography>

              <Stack spacing={2} sx={{ width: "100%" }}>
                <TextField
                  fullWidth
                  clabel={
                    <Typography variant="subtitle1">
                      Your name
                      <Typography component={"span"} color={"error"}>
                        *
                      </Typography>
                    </Typography>
                  }
                  {...getFieldProps("firstName")}
                  error={Boolean(touched.firstName && errors.firstName)}
                  helperText={touched.firstName && errors.firstName}
                />

                <TextField
                  fullWidth
                  clabel={
                    <Typography variant="subtitle1">
                      Last name
                      <Typography component={"span"} color={"error"}>
                        *
                      </Typography>
                    </Typography>
                  }
                  {...getFieldProps("lastName")}
                  error={Boolean(touched.lastName && errors.lastName)}
                  helperText={touched.lastName && errors.lastName}
                />

                <LocalizationProvider dateAdapter={AdapterDateFns}>
                  <MobileDatePicker
                    // label="For mobile"
                    {...getFieldProps("dob")}
                    error={Boolean(touched.dob && errors.dob)}
                    helperText={touched.dob && errors.dob}
                    onChange={(newValue) => {
                      setFieldValue("dob", newValue);
                    }}
                    renderInput={(params) => (
                      <TextField
                        {...params}
                        fullWidth
                        placeholder=""
                        clabel={
                          <Typography variant="subtitle1">
                            Your Birthday
                            <Typography component={"span"} color={"error"}>
                              *
                            </Typography>
                          </Typography>
                        }
                      />
                    )}
                  />
                </LocalizationProvider>
              </Stack>
            </Box>
            <Footer next back backClick={() => navigate(-1)} />
          </RootStyle>
        </Form>
      </FormikProvider>
    </Page>
  );
}
